create table dirkspzm32.isi_res_pruef_plan_data (
    sid                       varchar2(2 char) not null enable,
    firma_nr                  number(6, 0) not null enable,
    res_id                    number(*, 0),
    res_teilgewerk            number(*, 5),
    res_pruef_plan_nr         varchar2(100 char),
    res_pruef_plan_data_nr    number(*, 5),
    res_pruef_plan_data_value varchar2(100 char),
    created_date              date,
    created_login_id          number(*, 0),
    last_change_date          date,
    last_change_login_id      number(*, 0),
    id                        number(*, 0) not null enable
);

alter table dirkspzm32.isi_res_pruef_plan_data
    add constraint pk_isi_res_pruef_plan_data primary key ( id )
        using index enable;


